"""
ground_station/cli.py — DronePi Ground Station CLI.

Deployment model (Mission Planner style)
-----------------------------------------
Double-click the desktop icon → app starts silently → browser opens.
No Task Scheduler, no autostart, no login hooks. The app runs only when
you explicitly launch it, exactly like Mission Planner or QGroundControl.

The .pyw launcher (written by install()) handles everything:
  - Single-instance enforcement via lock file + PID check
  - Direct spawn of _daemon-worker and _ui-worker (no cli.py intermediary)
  - Socket polling loop until port is ready (no sleep/race condition)
  - Opens browser tab using --new-tab flag (prevents Edge PWA window)

Subcommands
-----------
  start          Start daemon + UI server (terminal use)
  stop           Stop daemon + UI server
  status         Show daemon/Ollama/RPi health table
  logs           Tail daemon log
  replay         Reprocess a specific flight by session ID
  install        Write icon, launcher, desktop shortcut
  uninstall      Remove shortcut + kill running processes
  _daemon-worker (internal) FlightReportDaemon.run_forever()
  _ui-worker     (internal) UIServer.serve_forever()
"""

import base64
import logging
import os
import platform
import subprocess
import sys
import time
import webbrowser
from pathlib import Path
from typing import Optional

import typer
from rich.console import Console
from rich.table import Table

app = Console()
cli = typer.Typer(
    name="ground-station",
    help="DronePi Ground Station — post-flight LLM report daemon.",
    add_completion=False,
)

log = logging.getLogger(__name__)

# ── Paths ──────────────────────────────────────────────────────────────────────

def _app_dir() -> Path:
    """ground_station_app/ — the folder containing pyproject.toml."""
    return Path(__file__).resolve().parent.parent

def _gs_dir() -> Path:
    """ground_station/ — the Python package folder."""
    return Path(__file__).resolve().parent

def _state_dir() -> Path:
    """~/.dronepi-ground/ — runtime state, logs, cache."""
    return Path.home() / ".dronepi-ground"

def _log_file() -> Path:
    return Path(os.environ.get("DRONEPI_LOG_FILE",
                               str(_state_dir() / "daemon.log")))

def _ui_pid_file() -> Path:
    return _state_dir() / "ui.pid"

def _daemon_pid_file() -> Path:
    return _state_dir() / "daemon.pid"

UI_PORT = int(os.environ.get("DRONEPI_UI_PORT", "8765"))

# ── ICO asset (base64-embedded DronePi logo) ──────────────────────────────────
_ICO_B64 = ""

def _write_icon() -> Path:
    ico_path = _state_dir() / "dronepi.ico"
    if not ico_path.exists():
        _state_dir().mkdir(parents=True, exist_ok=True)
        ico_path.write_bytes(base64.b64decode(_ICO_B64))
    return ico_path

# ── Port / browser helpers ─────────────────────────────────────────────────────

def _port_open(port: int) -> bool:
    """Non-blocking check: is anything listening on localhost:port?"""
    import socket
    try:
        with socket.create_connection(("127.0.0.1", port), timeout=0.5):
            return True
    except OSError:
        return False


def _wait_for_port(port: int, timeout: float = 15.0) -> bool:
    """Poll every 250 ms until port opens or timeout expires."""
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        if _port_open(port):
            return True
        time.sleep(0.25)
    return False


def _open_browser_tab(url: str) -> None:
    """
    Open url as a normal browser tab.
    Edge detects localhost and opens it as a PWA standalone window by default.
    Passing --new-tab explicitly forces tab mode and prevents the popup.
    """
    if platform.system() != "Windows":
        webbrowser.open(url)
        return

    candidates = [
        Path(os.environ.get("PROGRAMFILES(X86)", r"C:\Program Files (x86)"))
        / "Microsoft" / "Edge" / "Application" / "msedge.exe",
        Path(r"C:\Program Files\Microsoft\Edge\Application\msedge.exe"),
        Path(os.environ.get("PROGRAMFILES", r"C:\Program Files"))
        / "Google" / "Chrome" / "Application" / "chrome.exe",
        Path(os.environ.get("PROGRAMFILES(X86)", r"C:\Program Files (x86)"))
        / "Google" / "Chrome" / "Application" / "chrome.exe",
    ]
    for browser in candidates:
        if browser.exists():
            subprocess.Popen(
                [str(browser), "--new-tab", url],
                creationflags=0x08000000,  # CREATE_NO_WINDOW
            )
            return
    webbrowser.open(url)

# ── Process spawning ──────────────────────────────────────────────────────────

def _spawn_worker(worker: str, pid_file: Path) -> Optional[int]:
    """
    Spawn _daemon-worker or _ui-worker as a fully detached background process.
    Uses CREATE_NO_WINDOW + DETACHED_PROCESS so no console ever appears.
    Returns PID or None on failure.
    """
    log_path = _state_dir() / f"{worker.lstrip('_')}.log"
    _state_dir().mkdir(parents=True, exist_ok=True)
    cmd = [sys.executable, "-m", "ground_station.cli", worker]
    try:
        log_fh = open(log_path, "a")
        if platform.system() == "Windows":
            proc = subprocess.Popen(
                cmd,
                stdout=log_fh,
                stderr=log_fh,
                creationflags=(
                    0x08000000 |                        # CREATE_NO_WINDOW
                    0x00000008 |                        # DETACHED_PROCESS
                    subprocess.CREATE_NEW_PROCESS_GROUP
                ),
                close_fds=True,
            )
        else:
            proc = subprocess.Popen(
                cmd,
                stdout=log_fh,
                stderr=log_fh,
                start_new_session=True,
                close_fds=True,
            )
        pid_file.write_text(str(proc.pid), encoding="utf-8")
        return proc.pid
    except Exception as exc:
        log.error(f"Failed to spawn {worker}: {exc}")
        return None


def _ui_server_alive() -> bool:
    try:
        pid = int(_ui_pid_file().read_text().strip())
        if platform.system() == "Windows":
            r = subprocess.run(
                ["tasklist", "/FI", f"PID eq {pid}", "/NH"],
                capture_output=True, text=True, timeout=3,
            )
            return str(pid) in r.stdout
        else:
            os.kill(pid, 0)
            return True
    except Exception:
        return False


def _stop_ui_server() -> None:
    import signal as _signal
    try:
        pid = int(_ui_pid_file().read_text().strip())
        if platform.system() == "Windows":
            subprocess.run(["taskkill", "/F", "/PID", str(pid)],
                           capture_output=True, timeout=5)
        else:
            os.kill(pid, _signal.SIGTERM)
        _ui_pid_file().unlink(missing_ok=True)
    except (FileNotFoundError, ValueError, ProcessLookupError):
        pass
    except Exception as exc:
        log.warning(f"UI server stop error: {exc}")


def _configure_logging() -> None:
    _state_dir().mkdir(parents=True, exist_ok=True)
    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s  %(levelname)-7s  %(name)s  %(message)s",
        handlers=[
            logging.FileHandler(_log_file(), encoding="utf-8"),
            logging.StreamHandler(sys.stdout),
        ],
    )


def _check_rpi() -> bool:
    import httpx
    host = os.environ.get("DRONEPI_RPI_HOST", "10.42.0.1")
    port = os.environ.get("DRONEPI_RPI_PORT", "8080")
    try:
        with httpx.Client(timeout=httpx.Timeout(3.0)) as c:
            r = c.get(f"http://{host}:{port}/api/flights")
            return r.status_code == 200
    except Exception:
        return False

# ══════════════════════════════════════════════════════════════════════════════
# CLI commands
# ══════════════════════════════════════════════════════════════════════════════

@cli.command()
def start(
    open_browser: bool = typer.Option(
        True, "--no-browser/--open-browser",
        help="Skip opening the browser.",
    ),
) -> None:
    """Start the daemon and UI server."""
    from ground_station.process_manager import ProcessManager

    pm = ProcessManager()

    if pm.is_running():
        app.print("[yellow]Daemon already running.[/yellow]")
    else:
        pid = _spawn_worker("_daemon-worker", _daemon_pid_file())
        if pid:
            app.print(f"[green]Daemon started (pid={pid}).[/green]")
        else:
            app.print("[red]Failed to start daemon.[/red]")
            raise typer.Exit(1)

    if _ui_server_alive():
        app.print("[yellow]UI server already running.[/yellow]")
    else:
        pid = _spawn_worker("_ui-worker", _ui_pid_file())
        if pid:
            app.print(f"[green]UI server started (pid={pid}).[/green]")

    if open_browser:
        app.print("[dim]Waiting for UI server...[/dim]")
        _wait_for_port(UI_PORT, timeout=15)
        _open_browser_tab(f"http://localhost:{UI_PORT}")


@cli.command()
def stop() -> None:
    """Stop the daemon and UI server."""
    from ground_station.process_manager import ProcessManager
    pm = ProcessManager()

    if pm.stop_daemon():
        app.print("[green]Daemon stopped.[/green]")
    else:
        app.print("[yellow]Daemon was not running.[/yellow]")

    _stop_ui_server()
    app.print("[green]UI server stopped.[/green]")


@cli.command()
def status() -> None:
    """Show daemon, Ollama, and RPi connectivity status."""
    from ground_station.process_manager import ProcessManager
    from ground_station.ollama_client import OllamaClient

    pm     = ProcessManager()
    ollama = OllamaClient()

    table = Table(title="DronePi Ground Station Status", show_header=True)
    table.add_column("Component", style="cyan",  width=20)
    table.add_column("Status",    style="white",  width=15)
    table.add_column("Detail",    style="dim")

    pid = pm.daemon_pid()
    table.add_row(
        "Daemon",
        "[green]Running[/green]" if pid else "[red]Stopped[/red]",
        f"pid={pid}" if pid else "Run: ground-station start",
    )

    ui_alive = _ui_server_alive()
    table.add_row(
        "UI Server",
        "[green]Running[/green]" if ui_alive else "[red]Stopped[/red]",
        f"http://localhost:{UI_PORT}" if ui_alive else "",
    )

    ollama_ok = ollama.is_reachable()
    table.add_row(
        "Ollama",
        "[green]Reachable[/green]" if ollama_ok else "[red]Unreachable[/red]",
        ollama.host,
    )

    if ollama_ok:
        model_ok = ollama.model_available()
        table.add_row(
            "Model",
            "[green]Available[/green]" if model_ok else "[yellow]Not pulled[/yellow]",
            ollama.model,
        )

    rpi_ok = _check_rpi()
    rpi_host = os.environ.get("DRONEPI_RPI_HOST", "10.42.0.1")
    rpi_port = os.environ.get("DRONEPI_RPI_PORT", "8080")
    table.add_row(
        "RPi",
        "[green]Reachable[/green]" if rpi_ok else "[yellow]Unreachable[/yellow]",
        f"{rpi_host}:{rpi_port}",
    )

    app.print(table)


@cli.command()
def logs(
    lines: int   = typer.Option(50,    "--lines", "-n", help="Lines to show."),
    follow: bool = typer.Option(False, "--follow", "-f", help="Follow log output."),
) -> None:
    """Tail the daemon log."""
    log_path = _log_file()
    if not log_path.exists():
        app.print(f"[yellow]Log file not found: {log_path}[/yellow]")
        raise typer.Exit(1)

    if follow:
        if platform.system() == "Windows":
            subprocess.run(["powershell", "-Command",
                            f"Get-Content '{log_path}' -Wait -Tail {lines}"])
        else:
            subprocess.run(["tail", "-f", "-n", str(lines), str(log_path)])
    else:
        content = log_path.read_text(encoding="utf-8", errors="replace")
        app.print("\n".join(content.splitlines()[-lines:]))


@cli.command()
def replay(
    session_id: str = typer.Argument(..., help="Flight session ID to reprocess."),
    force: bool     = typer.Option(False, "--force", "-f",
                                   help="Reprocess even if already marked processed."),
) -> None:
    """Reprocess a specific flight (re-run Ollama report generation)."""
    from ground_station.flight_watcher import FlightWatcher
    from ground_station.ollama_client import OllamaClient, OllamaError
    from ground_station.orchestrator import FlightReportDaemon

    watcher = FlightWatcher()
    if force and watcher.is_processed(session_id):
        watcher._processed.discard(session_id)
        watcher._save_state()
        app.print(f"[yellow]Cleared processed state for {session_id}.[/yellow]")

    try:
        client = OllamaClient()
        client.ensure_ready()
    except OllamaError as exc:
        app.print(f"[red]Ollama not ready: {exc}[/red]")
        raise typer.Exit(1)

    app.print(f"[cyan]Replaying {session_id}...[/cyan]")
    daemon = FlightReportDaemon(ollama_client=client)
    ok = daemon.process_one(session_id)

    if ok:
        watcher.mark_processed(session_id)
        app.print(f"[green]Report generated for {session_id}.[/green]")
    else:
        app.print("[red]Report generation failed. Check logs.[/red]")
        raise typer.Exit(1)


@cli.command()
def install() -> None:
    """
    Write icon, launcher .pyw, and desktop shortcut.

    Mission Planner style — no Task Scheduler, no autostart.
    The app runs only when you open it, just like Mission Planner.
    Double-click the desktop shortcut to launch.
    """
    _state_dir().mkdir(parents=True, exist_ok=True)

    ico_path = _write_icon()
    app.print(f"[green]Icon written: {ico_path}[/green]")

    launcher = _write_launcher()
    app.print(f"[green]Launcher written: {launcher}[/green]")

    shortcut = _create_shortcut(launcher, ico_path)
    if shortcut:
        app.print(f"[green]Desktop shortcut created: {shortcut}[/green]")
    else:
        app.print("[yellow]Could not create shortcut automatically.[/yellow]")
        app.print(f"[dim]Create it manually pointing to: {launcher}[/dim]")

    app.print("\n[bold green]Installation complete.[/bold green]")
    app.print("[dim]Double-click the desktop shortcut to launch DronePi Ground Station.[/dim]")


@cli.command()
def uninstall() -> None:
    """Stop the app and remove the desktop shortcut."""
    stop()

    shortcut = _desktop_shortcut_path()
    if shortcut.exists():
        shortcut.unlink()
        app.print("[green]Desktop shortcut removed.[/green]")

    launcher = _app_dir() / "DronePi Ground Station.pyw"
    if launcher.exists():
        launcher.unlink()
        app.print("[green]Launcher removed.[/green]")

    app.print("[green]Uninstall complete.[/green]")


# ── Internal workers ──────────────────────────────────────────────────────────

@cli.command(name="_daemon-worker", hidden=True)
def daemon_worker() -> None:
    """Internal: FlightReportDaemon.run_forever(). Never call directly."""
    _configure_logging()
    from ground_station.orchestrator import FlightReportDaemon
    FlightReportDaemon().run_forever()


@cli.command(name="_ui-worker", hidden=True)
def ui_worker() -> None:
    """Internal: UIServer.serve_forever(). Never call directly."""
    _configure_logging()
    from ground_station.ui_server import UIServer
    UIServer(port=UI_PORT).serve_forever()

# ══════════════════════════════════════════════════════════════════════════════
# Launcher generator
# ══════════════════════════════════════════════════════════════════════════════

def _write_launcher() -> Path:
    """
    Write DronePi Ground Station.pyw — the desktop icon target.

    The .pyw file is a pythonw script (no console window).
    It embeds all paths as absolute strings resolved at install time so it
    works correctly regardless of current directory or Task Scheduler context.

    Single-instance logic
    ---------------------
    Uses a lock file containing the launcher's own PID. On double-click:
      - If port already open  → just open a browser tab and exit
      - If lock file holds live PID → another instance is starting → wait + tab
      - Otherwise → acquire lock → spawn workers → poll port → open tab → release

    No cli.py start is called — workers are spawned directly to avoid the
    rich/typer console flash.
    """
    launcher  = _app_dir() / "DronePi Ground Station.pyw"

    # Resolve browser paths at install time
    edge_path   = _find_browser("edge")
    chrome_path = _find_browser("chrome")

    # pythonw.exe suppresses the console window completely on Windows
    pythonw = Path(sys.executable).parent / "pythonw.exe"
    python  = str(pythonw) if pythonw.exists() else sys.executable

    code = f'''\
# DronePi Ground Station — desktop launcher
# Generated by: python ground_station/cli.py install
# Re-run install to regenerate. Do not edit manually.
import os, sys, socket, subprocess, time
from pathlib import Path

# ── Embedded absolute paths (resolved at install time) ────────────────────────
PYTHON      = r"{python}"
CLI_MODULE  = "ground_station.cli"
APP_DIR     = Path(r"{_app_dir()}")
STATE_DIR   = Path(r"{_state_dir()}")
DAEMON_PID  = STATE_DIR / "daemon.pid"
UI_PID      = STATE_DIR / "ui.pid"
DAEMON_LOG  = STATE_DIR / "daemon.log"
UI_LOG      = STATE_DIR / "ui.log"
LOCK        = STATE_DIR / "launcher.lock"
PORT        = {UI_PORT}
URL         = f"http://localhost:{{PORT}}"
EDGE        = r"{edge_path}"
CHROME      = r"{chrome_path}"

NO_WIN      = 0x08000000   # CREATE_NO_WINDOW
DETACH      = 0x00000008   # DETACHED_PROCESS
NEW_GRP     = 0x00000200   # CREATE_NEW_PROCESS_GROUP


def port_open():
    """Check if the UI server is already listening."""
    try:
        with socket.create_connection(("127.0.0.1", PORT), timeout=0.5):
            return True
    except OSError:
        return False


def wait_for_port(timeout=15.0):
    """Poll every 250ms until port opens or timeout expires."""
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        if port_open():
            return True
        time.sleep(0.25)
    return False


def open_tab():
    """Open browser tab via registry shell handler."""
    import os
    os.startfile(URL)
            return

    import webbrowser
    webbrowser.open(URL)


def pid_alive(pid):
    """Return True if a process with this PID is running."""
    try:
        import ctypes
        PROCESS_QUERY_LIMITED = 0x1000
        handle = ctypes.windll.kernel32.OpenProcess(
            PROCESS_QUERY_LIMITED, False, pid
        )
        if not handle:
            return False
        # Check if process has exited
        import ctypes.wintypes as wt
        code = wt.DWORD()
        ctypes.windll.kernel32.GetExitCodeProcess(handle, ctypes.byref(code))
        ctypes.windll.kernel32.CloseHandle(handle)
        return code.value == 259  # STILL_ACTIVE
    except Exception:
        return False


def acquire_lock():
    """
    Try to acquire the launcher lock.
    Returns True if we got the lock (safe to spawn).
    Returns False if another live launcher instance holds it.
    """
    STATE_DIR.mkdir(parents=True, exist_ok=True)
    if LOCK.exists():
        try:
            existing_pid = int(LOCK.read_text().strip())
            if pid_alive(existing_pid):
                return False  # Live instance — don't spawn
        except Exception:
            pass  # Unreadable or dead — overwrite
    LOCK.write_text(str(os.getpid()))
    return True


def release_lock():
    try:
        LOCK.unlink(missing_ok=True)
    except Exception:
        pass


def spawn(worker, pid_file, log_file):
    """Spawn a worker with no console window."""
    STATE_DIR.mkdir(parents=True, exist_ok=True)
    try:
        log_fh = open(log_file, "a")
        proc = subprocess.Popen(
            [PYTHON, "-m", CLI_MODULE, worker],
            stdout=log_fh,
            stderr=log_fh,
            creationflags=NO_WIN | DETACH | NEW_GRP,
            close_fds=True,
            cwd=str(APP_DIR),
        )
        Path(pid_file).write_text(str(proc.pid))
    except Exception as exc:
        open(log_file, "a").write(f"Launcher: failed to spawn {{worker}}: {{exc}}\\n")


# ── Entry point ───────────────────────────────────────────────────────────────

# Fast path: already running — just open a tab
if port_open():
    open_tab()
    sys.exit(0)

# Another launcher instance is currently starting up — wait then open tab
if not acquire_lock():
    if wait_for_port(timeout=12):
        open_tab()
    sys.exit(0)

# We have the lock — spawn workers and wait for the UI to come up
try:
    spawn("_daemon-worker", DAEMON_PID, DAEMON_LOG)
    spawn("_ui-worker",     UI_PID,     UI_LOG)

    if wait_for_port(timeout=15):
        open_tab()
    else:
        open_tab()  # Open anyway — UI will show an error state
finally:
    release_lock()
'''
    launcher.write_text(code, encoding="utf-8")
    return launcher


def _find_browser(name: str) -> str:
    """Find the absolute path of Edge or Chrome. Returns '' if not found."""
    if name == "edge":
        candidates = [
            Path(os.environ.get("PROGRAMFILES(X86)", r"C:\Program Files (x86)"))
            / "Microsoft" / "Edge" / "Application" / "msedge.exe",
            Path(r"C:\Program Files\Microsoft\Edge\Application\msedge.exe"),
        ]
    else:
        candidates = [
            Path(os.environ.get("PROGRAMFILES", r"C:\Program Files"))
            / "Google" / "Chrome" / "Application" / "chrome.exe",
            Path(os.environ.get("PROGRAMFILES(X86)", r"C:\Program Files (x86)"))
            / "Google" / "Chrome" / "Application" / "chrome.exe",
        ]
    for c in candidates:
        if c.exists():
            return str(c)
    return ""


def _desktop_shortcut_path() -> Path:
    """Resolve Desktop correctly on any Windows config including OneDrive."""
    if platform.system() == "Windows":
        try:
            import ctypes, ctypes.wintypes
            buf = ctypes.create_unicode_buffer(ctypes.wintypes.MAX_PATH)
            ctypes.windll.shell32.SHGetFolderPathW(0, 0x0000, 0, 0, buf)
            if buf.value:
                return Path(buf.value) / "DronePi Ground Station.lnk"
        except Exception:
            pass
    return Path.home() / "Desktop" / "DronePi Ground Station.lnk"


def _create_shortcut(launcher: Path, ico_path: Path) -> Optional[Path]:
    """
    Create a Windows .lnk shortcut pointing to the .pyw launcher.
    Uses pythonw.exe as the target so no console window ever appears.
    WindowStyle=7 = minimised/hidden — the .pyw itself manages the UI.
    """
    if platform.system() != "Windows":
        return None

    shortcut = _desktop_shortcut_path()

    # Use pythonw.exe to avoid any console window
    pythonw = Path(sys.executable).parent / "pythonw.exe"
    target  = str(pythonw) if pythonw.exists() else sys.executable

    try:
        ps = f"""
$ws  = New-Object -ComObject WScript.Shell
$lnk = $ws.CreateShortcut('{shortcut}')
$lnk.TargetPath      = '{target}'
$lnk.Arguments       = '"{launcher}"'
$lnk.WorkingDirectory= '{launcher.parent}'
$lnk.IconLocation    = '{ico_path}'
$lnk.Description     = 'DronePi Ground Station'
$lnk.WindowStyle     = 7
$lnk.Save()
"""
        result = subprocess.run(
            ["powershell", "-NoProfile", "-Command", ps],
            capture_output=True, text=True, timeout=15,
        )
        if result.returncode == 0:
            return shortcut
        log.warning(f"Shortcut creation failed: {result.stderr[:200]}")
        return None
    except Exception as exc:
        log.warning(f"Shortcut creation error: {exc}")
        return None


if __name__ == "__main__":
    cli()
